30	    private TableDefinition createUsersTable() {
31	        return service.createTable("Users",
32	                List.of(new KeySchemaElement("userId", "HASH")),
33	                List.of(new AttributeDefinition("userId", "S")),
34	                5L, 5L);
35	    }
36	
37	    private TableDefinition createOrdersTable() {
38	        return service.createTable("Orders",
39	                List.of(
40	                        new KeySchemaElement("customerId", "HASH"),
41	                        new KeySchemaElement("orderId", "RANGE")),
42	                List.of(
43	                        new AttributeDefinition("customerId", "S"),
44	                        new AttributeDefinition("orderId", "S")),
45	                5L, 5L);
46	    }
47	
48	    private ObjectNode attributeValue(String type, String value) {
49	        ObjectNode attrValue = mapper.createObjectNode();
50	        attrValue.put(type, value);
51	        return attrValue;
52	    }
53	
54	    private ObjectNode item(String... kvPairs) {
55	        ObjectNode node = mapper.createObjectNode();
56	        for (int i = 0; i < kvPairs.length; i += 2) {
57	            node.set(kvPairs[i], attributeValue("S", kvPairs[i + 1]));
58	        }
59	        return node;
60	    }
