535	    @Test
536	    void updateItemSetIfNotExistsUsesFallbackWhenCheckAttrAbsentAndAttrNameDiffers() {
537	        // SET a = if_not_exists(b, :v) where b is absent → a must be set to :v
538	        createUsersTable();
539	
540	        // Item has no "source" attribute
541	        service.putItem("Users", item("userId", "u-fallback"));
542	
543	        ObjectNode key = item("userId", "u-fallback");
544	
545	        ObjectNode exprValues = mapper.createObjectNode();
546	        ObjectNode fallbackVal = mapper.createObjectNode(); fallbackVal.put("S", "fallback");
547	        exprValues.set(":v", fallbackVal);
548	
549	        service.updateItem("Users", key, null,
550	                "SET target = if_not_exists(source, :v)",
