1034	    private String applyAddClause(ObjectNode item, String clause,
1035	                                  JsonNode exprAttrNames, JsonNode exprAttrValues) {
1036	        while (!clause.isEmpty()) {
1037	            String upper = clause.toUpperCase();
1038	            if (upper.startsWith("SET ") || upper.startsWith("REMOVE ") || upper.startsWith("DELETE ")) {
1039	                break;
1040	            }
1041	
1042	            // Parse "attr :val"
1043	            String[] parts = clause.split("\\s+", 3);
1044	            if (parts.length < 2) break;
1045	
1046	            String attrName = resolveAttributeName(parts[0], exprAttrNames);
1047	            String valuePlaceholder = parts[1].replaceAll(",.*", "").trim();
1048	
1049	            if (valuePlaceholder.startsWith(":") && exprAttrValues != null) {
1050	                JsonNode addValue = exprAttrValues.get(valuePlaceholder);
1051	                if (addValue != null) {
1052	                    JsonNode existingValue = item.get(attrName);
1053	                    JsonNode newValue = applyAddOperation(existingValue, addValue);
1054	                    item.set(attrName, newValue);
1055	                }
1056	            }
1057	
1058	            // Advance past this assignment
1059	            int commaIdx = findNextComma(clause);
1060	            if (commaIdx >= 0) {
1061	                clause = clause.substring(commaIdx + 1).trim();
1062	            } else {
1063	                int nextClause = findNextClauseKeyword(clause);
1064	                clause = nextClause >= 0 ? clause.substring(nextClause).trim() : "";
1065	            }
1066	        }
1067	        return clause;
1068	    }
