1141	    String resolveAttributeName(String nameOrPlaceholder, JsonNode exprAttrNames) {
1142	        nameOrPlaceholder = trimBalancedOuterParens(nameOrPlaceholder).trim();
1143	        if (nameOrPlaceholder.startsWith("#") && exprAttrNames != null) {
1144	            JsonNode resolved = exprAttrNames.get(nameOrPlaceholder);
1145	            if (resolved != null) {
1146	                return resolved.asText();
1147	            }
1148	        }
1149	        return nameOrPlaceholder;
1150	    }
